  pm: pmHours,
  corrective: 0, // TODO: Integrate with unavailability events
  overhaul: 0, // TODO: Separate overhaul tracking
  total: pmHours,
};

const available: AvailableHours = {
  regular: regularHours,
  overtime: overtimeMax,
  total: regularHours + overtimeMax,
};

const variance = available.total - required.total;
const utilizationPct = available.total > 0 ? required.total / available.total : 0;

projections.push({
  depotId,
  depotCode: depot.code,

      overtime: parseFloat(projection.availableOvertimeHours ?? '0'),
      total: availableTotal,
    },
    varianceHours,
    utilizationPct: Math.round(utilizationPct * 10) / 10,
    isOverloaded: requiredTotal > availableTotal,
    isUnderutilized: requiredTotal < availableTotal * 0.7,
    pendingAdjustments: 0, // TODO: Count adjustments when relation is loaded
  };
});

